    preference = Preference.objects.create(name="Jordan", preferred_sport="", preferred_musician=None)
    assert PreferenceSchema.from_django(preference).dict() == {
        "id": 1,
        "name": "Jordan",
        "preferred_food": "ba",
        "preferred_group": 1,
        "preferred_sport": "",
        'preferred_musician': None
